async (params, browser) => {
  // Search Canva templates
  await browser.open(`https://www.canva.com/search/templates?q=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('a[href*=\'/templates/\'], img, [role=\'list\'], [role=\'listitem\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract template results
  const search_results = await browser.evaluate(`const results = []; const seen = new Set(); const links = document.querySelectorAll('a[href*="/templates/"]'); for (let i = 0; i < links.length && results.length < 15; i++) { const el = links[i]; const href = el.href || ''; if (!href || seen.has(href)) continue; seen.add(href); const imgEl = el.querySelector('img'); const ariaLabel = el.getAttribute('aria-label') || ''; const titleEl = el.querySelector('h3, h4, [aria-label]'); const title = ariaLabel || (titleEl ? (titleEl.getAttribute('aria-label') || titleEl.textContent.trim()) : ''); if (!title && !imgEl) continue; const proEl = el.querySelector('[aria-label*="Pro"], [aria-label*="premium"]'); results.push({ title: title, is_premium: !!proEl, url: href, image: imgEl ? imgEl.getAttribute('src') : '' }); } if (results.length === 0) { const allItems = document.querySelectorAll('[role="listitem"], [role="list"] > div'); for (let i = 0; i < Math.min(allItems.length, 15); i++) { const el = allItems[i]; const linkEl = el.querySelector('a[href*="/templates/"]'); const imgEl = el.querySelector('img'); const titleEl = el.querySelector('[aria-label], h3, h4'); results.push({ title: titleEl ? (titleEl.getAttribute('aria-label') || titleEl.textContent.trim()) : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
